1	import Link from "next/link";
2	import { Suspense } from "react";
3	import TemporalReplayBar from "@/components/TemporalReplayBar";
4	import ConfidenceTierSigil from "@/components/ConfidenceTierSigil";
5	import SculptureBackdrop from "@/components/SculptureBackdrop";
6	import { db } from "@/lib/db";
7	import { founderDisplayName } from "@/lib/founderDisplay";
8	import { fetchReplayConclusions } from "@/lib/noosphereReplayBridge";
9	import { AS_OF_ISO } from "@/lib/replayDate";
10	import { requireTenantContext } from "@/lib/tenant";
11	
12	/**
13	 * Conclusions list. Each row shows the inline confidence-tier sigil
14	 * (firm / founder / open / retired) next to the text, so a glance down
15	 * the page reveals the firm's belief-structure at a glance.
16	 *
17	 * Filter chips at the top use the same sigil as a prefix, reinforcing
18	 * the semantic colour-coding.
19	 */
20	
21	const TIERS = ["firm", "founder", "open", "retired"] as const;
22	const PAGE_SIZE = 40;
23	
24	type ConclusionsSearchParams = {
25	  tier?: string;
26	  topic?: string;
27	  asOf?: string;
28	  q?: string;
29	  page?: string;
30	  tab?: string;
31	};
32	
33	function urlFor(basePath: string, tab: string, params: URLSearchParams) {
34	  if (basePath === "/knowledge") params.set("tab", tab);
35	  const qs = params.toString();
36	  return `${basePath}${qs ? `?${qs}` : ""}`;
37	}
38	
39	async function ConclusionsContent({
40	  searchParams,
41	  basePath = "/conclusions",
42	}: {
43	  searchParams: Promise<ConclusionsSearchParams>;
44	  basePath?: string;
45	}) {
46	  const sp = await searchParams;
47	  const asOf = sp.asOf;
48	  const replay = Boolean(asOf && AS_OF_ISO.test(asOf));
49	
50	  if (replay) {
51	    const { rows, error } = await fetchReplayConclusions(asOf!);
52	    return (
53	      <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
54	        <Suspense fallback={null}>
55	          <TemporalReplayBar />
56	        </Suspense>
57	        <h1
58	          style={{
59	            fontFamily: "'Cinzel', serif",
60	            color: "var(--amber)",
61	            letterSpacing: "0.06em",
62	            fontSize: "1.45rem",
63	            fontWeight: 500,
64	            textShadow: "var(--glow-sm)",
65	            margin: 0,
66	          }}
67	        >
68	          Conclusions
69	        </h1>
70	        <p
71	          style={{
72	            color: "var(--ember)",
73	            fontSize: "0.85rem",
74	            marginBottom: "1rem",
75	          }}
76	        >
77	          Replay mode: conclusions consistent with Noosphere evidence as of{" "}
78	          <strong>{asOf}</strong> (see Operations manual for imperfections).
79	        </p>
80	        {error ? (
81	          <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem" }}>
82	            {error}
83	          </p>
84	        ) : null}
85	        <ul
86	          style={{
87	            listStyle: "none",
88	            padding: 0,
89	            margin: 0,
90	            display: "flex",
91	            flexDirection: "column",
92	            gap: "0.75rem",
93	          }}
94	        >
95	          {rows.map((c) => (
96	            <li
97	              key={c.id}
98	              className="portal-card"
99	              style={{ padding: "1rem 1.25rem" }}
100	            >
101	              <Link
102	                href={`/conclusions/${c.id}`}
103	                style={{
104	                  textDecoration: "none",
105	                  color: "inherit",
106	                  display: "flex",
107	                  gap: "0.9rem",
108	                  alignItems: "flex-start",
109	                }}
110	              >
111	                <ConfidenceTierSigil tier={c.confidence_tier || "open"} />
112	                <div style={{ minWidth: 0, flex: 1 }}>
113	                  <div
114	                    className="mono"
115	                    style={{
116	                      fontSize: "0.62rem",
117	                      color: "var(--amber-dim)",
118	                      textTransform: "uppercase",
119	                      letterSpacing: "0.12em",
120	                      display: "flex",
121	                      gap: "0.5rem",
122	                    }}
123	                  >
124	                    <span>
125	                      {c.confidence_tier || ""}
126	                      {c.created_at
127	                        ? ` · recorded ${String(c.created_at).slice(0, 10)}`
128	                        : ""}
129	                    </span>
130	                    <span style={{ color: "var(--ember)", marginLeft: "auto" }}>
131	                      exits replay →
132	                    </span>
133	                  </div>
134	                  <p style={{ marginTop: "0.45rem", color: "var(--parchment)" }}>
135	                    {c.text}
136	                  </p>
137	                  {c.rationale ? (
138	                    <p
139	                      style={{
140	                        marginTop: "0.35rem",
141	                        fontSize: "0.8rem",
142	                        color: "var(--parchment-dim)",
143	                      }}
144	                    >
145	                      {c.rationale}
146	                    </p>
147	                  ) : null}
148	                </div>
149	              </Link>
150	            </li>
151	          ))}
152	        </ul>
153	      </main>
154	    );
155	  }
156	
157	  const tenant = await requireTenantContext();
158	  if (!tenant) {
159	    return null;
160	  }
161	
162	  const page = Math.max(1, parseInt(sp.page || "1", 10));
163	  const q = sp.q?.trim() || "";
164	
165	  const where: {
166	    organizationId: string;
167	    confidenceTier?: string;
168	    topicHint?: { contains: string };
169	    OR?: Array<Record<string, { contains: string; mode: "insensitive" }>>;
170	  } = { organizationId: tenant.organizationId };
171	  if (sp.tier) where.confidenceTier = sp.tier;
172	  if (sp.topic) where.topicHint = { contains: sp.topic };
173	  if (q) {
174	    where.OR = [
175	      { text: { contains: q, mode: "insensitive" } },
176	      { rationale: { contains: q, mode: "insensitive" } },
177	      { topicHint: { contains: q, mode: "insensitive" } },
178	    ];
179	  }
180	
181	  const [rows, total] = await Promise.all([
182	    db.conclusion.findMany({
183	      where,
184	      orderBy: { createdAt: "desc" },
185	      take: PAGE_SIZE + 1,
186	      skip: (page - 1) * PAGE_SIZE,
187	      include: {
188	        attributedFounder: {
189	          select: { displayName: true, name: true, username: true },
190	        },
191	      },
192	    }),
193	    db.conclusion.count({ where }),
194	  ]);
195	  const hasNext = rows.length > PAGE_SIZE;
196	  const display = hasNext ? rows.slice(0, PAGE_SIZE) : rows;
197	
198	  // Page URLs preserve filter state; tier chips reset `page` so the
199	  // new filter's first page is always what the user sees after clicking.
200	  function buildPageUrl(p: number): string {
201	    const params = new URLSearchParams();
202	    if (sp.tier) params.set("tier", sp.tier);
203	    if (sp.topic) params.set("topic", sp.topic);
204	    if (q) params.set("q", q);
205	    if (p > 1) params.set("page", String(p));
206	    return urlFor(basePath, "conclusions", params);
207	  }
208	
209	  function buildTierUrl(tier: string | null): string {
210	    const params = new URLSearchParams();
211	    if (tier) params.set("tier", tier);
212	    if (q) params.set("q", q);
213	    return urlFor(basePath, "conclusions", params);
214	  }
215	
216	  function buildClearUrl(): string {
217	    const params = new URLSearchParams();
218	    if (sp.tier) params.set("tier", sp.tier);
219	    if (sp.topic) params.set("topic", sp.topic);
220	    return urlFor(basePath, "conclusions", params);
221	  }
222	
223	  function buildTopicUrl(topic: string): string {
224	    const params = new URLSearchParams();
225	    params.set("topic", topic);
226	    if (q) params.set("q", q);
227	    return urlFor(basePath, "conclusions", params);
228	  }
229	
230	  return (
231	    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
232	      <SculptureBackdrop
233	        src="/sculptures/discobolus-alt.mesh.bin"
234	        side="right"
235	        yawSpeed={0.01}
236	      />
237	
238	      <main
239	        style={{
240	          position: "relative",
241	          zIndex: 1,
242	          maxWidth: "960px",
243	          margin: "0 auto",
244	          padding: "2rem 2rem 3rem",
245	        }}
246	      >
247	        <Suspense fallback={null}>
248	          <TemporalReplayBar />
249	        </Suspense>
250	
251	        <header className="page-header">
252	          <div className="page-header__lead">
253	            <p className="page-header__kicker">The firm&apos;s canon</p>
254	            <h1 className="page-header__title">Conclusions</h1>
255	            <p className="page-header__desc">
256	              Commitments that move deliberation from potential to action.
257	              Filter by confidence tier, topic, or search the full text below.
258	            </p>
259	          </div>
260	        </header>
261	
262	        <form
263	          action={basePath}
264	          method="get"
265	          style={{ display: "flex", gap: "0.5rem", marginBottom: "1rem", flexWrap: "wrap" }}
266	        >
267	          {basePath === "/knowledge" ? (
268	            <input type="hidden" name="tab" value="conclusions" />
269	          ) : null}
270	          <input
271	            type="text"
272	            name="q"
273	            defaultValue={q}
274	            placeholder="Search conclusions…"
275	            style={{
276	              flex: 1,
277	              minWidth: "12rem",
278	              maxWidth: "24rem",
279	              padding: "0.4rem 0.75rem",
280	              fontSize: "0.8rem",
281	              fontFamily: "inherit",
282	              background: "transparent",
283	              border: "1px solid var(--border)",
284	              color: "var(--parchment)",
285	              borderRadius: 2,
286	            }}
287	          />
288	          {sp.tier && <input type="hidden" name="tier" value={sp.tier} />}
289	          {sp.topic && <input type="hidden" name="topic" value={sp.topic} />}
290	          <button type="submit" className="btn" style={{ fontSize: "0.65rem" }}>
291	            Search
292	          </button>
293	          {q && (
294	            <Link
295	              href={buildClearUrl()}
296	              className="btn"
297	              style={{ fontSize: "0.65rem", textDecoration: "none" }}
298	            >
299	              Clear
300	            </Link>
301	          )}
302	        </form>
303	
304	        {q && (
305	          <p
