import Link from "next/link";
import { Suspense } from "react";
import TemporalReplayBar from "@/components/TemporalReplayBar";
import ConfidenceTierSigil from "@/components/ConfidenceTierSigil";
import SculptureBackdrop from "@/components/SculptureBackdrop";
import { db } from "@/lib/db";
import { founderDisplayName } from "@/lib/founderDisplay";
import { fetchReplayConclusions } from "@/lib/noosphereReplayBridge";
import { AS_OF_ISO } from "@/lib/replayDate";
import { requireTenantContext } from "@/lib/tenant";

/**
 * Conclusions list. Each row shows the inline confidence-tier sigil
 * (firm / founder / open / retired) next to the text, so a glance down
 * the page reveals the firm's belief-structure at a glance.
 *
 * Filter chips at the top use the same sigil as a prefix, reinforcing
 * the semantic colour-coding.
 */

const TIERS = ["firm", "founder", "open", "retired"] as const;
const PAGE_SIZE = 40;

type ConclusionsSearchParams = {
  tier?: string;
  topic?: string;
  asOf?: string;
  q?: string;
  page?: string;
  tab?: string;
};

function urlFor(basePath: string, tab: string, params: URLSearchParams) {
  if (basePath === "/knowledge") params.set("tab", tab);
  const qs = params.toString();
  return `${basePath}${qs ? `?${qs}` : ""}`;
}

async function ConclusionsContent({
  searchParams,
  basePath = "/conclusions",
}: {
  searchParams: Promise<ConclusionsSearchParams>;
  basePath?: string;
}) {
  const sp = await searchParams;
  const asOf = sp.asOf;
  const replay = Boolean(asOf && AS_OF_ISO.test(asOf));

  if (replay) {
    const { rows, error } = await fetchReplayConclusions(asOf!);
    return (
      <main style={{ maxWidth: "960px", margin: "0 auto", padding: "3rem 2rem" }}>
        <Suspense fallback={null}>
          <TemporalReplayBar />
        </Suspense>
        <h1
          style={{
            fontFamily: "'Cinzel', serif",
            color: "var(--amber)",
            letterSpacing: "0.06em",
            fontSize: "1.45rem",
            fontWeight: 500,
            textShadow: "var(--glow-sm)",
            margin: 0,
          }}
        >
          Conclusions
        </h1>
        <p
          style={{
            color: "var(--ember)",
            fontSize: "0.85rem",
            marginBottom: "1rem",
          }}
        >
          Replay mode: conclusions consistent with Noosphere evidence as of{" "}
          <strong>{asOf}</strong> (see Operations manual for imperfections).
        </p>
        {error ? (
          <p style={{ color: "var(--parchment-dim)", fontSize: "0.85rem" }}>
            {error}
          </p>
        ) : null}
        <ul
          style={{
            listStyle: "none",
            padding: 0,
            margin: 0,
            display: "flex",
            flexDirection: "column",
            gap: "0.75rem",
          }}
        >
          {rows.map((c) => (
            <li
              key={c.id}
              className="portal-card"
              style={{ padding: "1rem 1.25rem" }}
            >
              <Link
                href={`/conclusions/${c.id}`}
                style={{
                  textDecoration: "none",
                  color: "inherit",
                  display: "flex",
                  gap: "0.9rem",
                  alignItems: "flex-start",
                }}
              >
                <ConfidenceTierSigil tier={c.confidence_tier || "open"} />
                <div style={{ minWidth: 0, flex: 1 }}>
                  <div
                    className="mono"
                    style={{
                      fontSize: "0.62rem",
                      color: "var(--amber-dim)",
                      textTransform: "uppercase",
                      letterSpacing: "0.12em",
                      display: "flex",
                      gap: "0.5rem",
                    }}
                  >
                    <span>
                      {c.confidence_tier || ""}
                      {c.created_at
                        ? ` · recorded ${String(c.created_at).slice(0, 10)}`
                        : ""}
                    </span>
                    <span style={{ color: "var(--ember)", marginLeft: "auto" }}>
                      exits replay →
                    </span>
                  </div>
                  <p style={{ marginTop: "0.45rem", color: "var(--parchment)" }}>
                    {c.text}
                  </p>
                  {c.rationale ? (
                    <p
                      style={{
                        marginTop: "0.35rem",
                        fontSize: "0.8rem",
                        color: "var(--parchment-dim)",
                      }}
                    >
                      {c.rationale}
                    </p>
                  ) : null}
                </div>
              </Link>
            </li>
          ))}
        </ul>
      </main>
    );
  }

  const tenant = await requireTenantContext();
  if (!tenant) {
    return null;
  }

  const page = Math.max(1, parseInt(sp.page || "1", 10));
  const q = sp.q?.trim() || "";

  const where: {
    organizationId: string;
    confidenceTier?: string;
    topicHint?: { contains: string };
    OR?: Array<Record<string, { contains: string; mode: "insensitive" }>>;
  } = { organizationId: tenant.organizationId };
  if (sp.tier) where.confidenceTier = sp.tier;
  if (sp.topic) where.topicHint = { contains: sp.topic };
  if (q) {
    where.OR = [
      { text: { contains: q, mode: "insensitive" } },
      { rationale: { contains: q, mode: "insensitive" } },
      { topicHint: { contains: q, mode: "insensitive" } },
    ];
  }

  const [rows, total] = await Promise.all([
    db.conclusion.findMany({
      where,
      orderBy: { createdAt: "desc" },
      take: PAGE_SIZE + 1,
      skip: (page - 1) * PAGE_SIZE,
      include: {
        attributedFounder: {
          select: { displayName: true, name: true, username: true },
        },
      },
    }),
    db.conclusion.count({ where }),
  ]);
  const hasNext = rows.length > PAGE_SIZE;
  const display = hasNext ? rows.slice(0, PAGE_SIZE) : rows;

  // Page URLs preserve filter state; tier chips reset `page` so the
  // new filter's first page is always what the user sees after clicking.
  function buildPageUrl(p: number): string {
    const params = new URLSearchParams();
    if (sp.tier) params.set("tier", sp.tier);
    if (sp.topic) params.set("topic", sp.topic);
    if (q) params.set("q", q);
    if (p > 1) params.set("page", String(p));
    return urlFor(basePath, "conclusions", params);
  }

  function buildTierUrl(tier: string | null): string {
    const params = new URLSearchParams();
    if (tier) params.set("tier", tier);
    if (q) params.set("q", q);
    return urlFor(basePath, "conclusions", params);
  }

  function buildClearUrl(): string {
    const params = new URLSearchParams();
    if (sp.tier) params.set("tier", sp.tier);
    if (sp.topic) params.set("topic", sp.topic);
    return urlFor(basePath, "conclusions", params);
  }

  function buildTopicUrl(topic: string): string {
    const params = new URLSearchParams();
    params.set("topic", topic);
    if (q) params.set("q", q);
    return urlFor(basePath, "conclusions", params);
  }

  return (
    <div style={{ position: "relative", overflow: "hidden", minHeight: "80vh" }}>
      <SculptureBackdrop
        src="/sculptures/discobolus-alt.mesh.bin"
        side="right"
        yawSpeed={0.01}
      />

      <main
        style={{
          position: "relative",
          zIndex: 1,
          maxWidth: "960px",
          margin: "0 auto",
          padding: "2rem 2rem 3rem",
        }}
      >
        <Suspense fallback={null}>
          <TemporalReplayBar />
        </Suspense>

        <header className="page-header">
          <div className="page-header__lead">
            <p className="page-header__kicker">The firm&apos;s canon</p>
            <h1 className="page-header__title">Conclusions</h1>
            <p className="page-header__desc">
              Commitments that move deliberation from potential to action.
              Filter by confidence tier, topic, or search the full text below.
            </p>
          </div>
        </header>

        <form
          action={basePath}
          method="get"
          style={{ display: "flex", gap: "0.5rem", marginBottom: "1rem", flexWrap: "wrap" }}
        >
          {basePath === "/knowledge" ? (
            <input type="hidden" name="tab" value="conclusions" />
          ) : null}
          <input
            type="text"
            name="q"
            defaultValue={q}
            placeholder="Search conclusions…"
            style={{
              flex: 1,
              minWidth: "12rem",
              maxWidth: "24rem",
              padding: "0.4rem 0.75rem",
              fontSize: "0.8rem",
              fontFamily: "inherit",
              background: "transparent",
              border: "1px solid var(--border)",
              color: "var(--parchment)",
              borderRadius: 2,
            }}
          />
          {sp.tier && <input type="hidden" name="tier" value={sp.tier} />}
          {sp.topic && <input type="hidden" name="topic" value={sp.topic} />}
          <button type="submit" className="btn" style={{ fontSize: "0.65rem" }}>
            Search
          </button>
          {q && (
            <Link
              href={buildClearUrl()}
              className="btn"
              style={{ fontSize: "0.65rem", textDecoration: "none" }}
            >
              Clear
            </Link>
          )}
        </form>

        {q && (
          <p
            style={{
              fontSize: "0.7rem",
              color: "var(--parchment-dim)",
              marginBottom: "0.75rem",
            }}
          >
            {total} result{total !== 1 ? "s" : ""} for &ldquo;{q}&rdquo;
          </p>
        )}

        <p
          className="mono"
          style={{
            color: "var(--amber-dim)",
            marginBottom: "0.75rem",
            fontSize: "0.62rem",
            letterSpacing: "0.2em",
            textTransform: "uppercase",
          }}
        >
          Filtra · Quick filters
        </p>
        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "0.5rem",
            marginBottom: "1.75rem",
            alignItems: "center",
          }}
        >
          <Link
            href={buildTierUrl(null)}
            className="btn"
            style={{ fontSize: "0.7rem", textDecoration: "none" }}
          >
            All
          </Link>
          {TIERS.map((t) => (
            <Link
              key={t}
              href={buildTierUrl(t)}
              className="btn"
              style={{
                fontSize: "0.7rem",
                textDecoration: "none",
                display: "inline-flex",
                alignItems: "center",
                gap: "0.5rem",
                ...(sp.tier === t
                  ? {
                      borderColor: "var(--amber)",
                      color: "var(--amber)",
                    }
                  : {}),
              }}
            >
              <ConfidenceTierSigil tier={t} size="0.55rem" />
              <span>{t}</span>
            </Link>
          ))}
          <Link
            href={buildTopicUrl("method")}
            className="btn"
            style={{ fontSize: "0.7rem", textDecoration: "none" }}
          >
            topic: method
          </Link>
        </div>

        {display.length === 0 ? (
          <div
            className="ascii-frame"
            data-label="VACUUM · EMPTY"
            style={{ padding: "2rem 1rem", textAlign: "center" }}
          >
            <p
              style={{
                fontFamily: "'EB Garamond', serif",
                fontStyle: "italic",
                fontSize: "1.1rem",
                color: "var(--parchment)",
                margin: 0,
              }}
            >
              Nihil adhuc conclusum.
            </p>
            <p
              className="mono"
              style={{
                fontSize: "0.7rem",
                color: "var(--parchment-dim)",
                marginTop: "0.4rem",
              }}
            >
              No conclusions yet — nothing for the firm to stand behind.
            </p>
          </div>
        ) : (
          <ul
            style={{
              listStyle: "none",
              padding: 0,
              margin: 0,
              display: "flex",
              flexDirection: "column",
              gap: "0.75rem",
            }}
          >
            {display.map((c) => (
              <li
                key={c.id}
                className="portal-card"
                style={{ padding: "1rem 1.25rem" }}
              >
                <Link
                  href={`/conclusions/${c.id}`}
                  style={{
                    textDecoration: "none",
                    color: "inherit",
                    display: "flex",
                    gap: "0.9rem",
                    alignItems: "flex-start",
                  }}
                >
                  <ConfidenceTierSigil tier={c.confidenceTier} />
                  <div style={{ minWidth: 0, flex: 1 }}>
                    <div
                      className="mono"
                      style={{
                        fontSize: "0.62rem",
                        color: "var(--amber-dim)",
                        textTransform: "uppercase",
                        letterSpacing: "0.12em",
                      }}
                    >
                      {c.confidenceTier}
                      {c.topicHint ? ` · ${c.topicHint}` : ""}
                      {c.attributedFounder
                        ? ` · ${founderDisplayName(c.attributedFounder)}`
                        : ""}
                    </div>
                    <p
                      style={{
                        marginTop: "0.5rem",
                        color: "var(--parchment)",
                      }}
                    >
                      {c.text}
                    </p>
                    {c.rationale && (
                      <p
                        style={{
                          marginTop: "0.35rem",
                          fontSize: "0.8rem",
                          color: "var(--parchment-dim)",
                        }}
                      >
                        {c.rationale}
                      </p>
                    )}
                  </div>
                </Link>
              </li>
            ))}
          </ul>
        )}

        {display.length > 0 && (
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              marginTop: "1.5rem",
              padding: "0.75rem 0",
              borderTop: "1px solid var(--border)",
            }}
          >
            <span style={{ fontSize: "0.7rem", color: "var(--parchment-dim)" }}>
              {total} conclusion{total !== 1 ? "s" : ""} · page {page}
            </span>
            <div style={{ display: "flex", gap: "0.5rem" }}>
              {page > 1 && (
                <Link
                  href={buildPageUrl(page - 1)}
                  className="btn"
                  style={{ fontSize: "0.65rem", textDecoration: "none" }}
                >
                  ← Previous
                </Link>
              )}
              {hasNext && (
                <Link
                  href={buildPageUrl(page + 1)}
                  className="btn"
                  style={{ fontSize: "0.65rem", textDecoration: "none" }}
                >
                  Next →
                </Link>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default async function ConclusionsPage({
  searchParams,
}: {
  searchParams: Promise<ConclusionsSearchParams>;
}) {
  return ConclusionsContent({ searchParams });
}

