13	import { type HotkeyBinding } from "@/lib/hotkeys";
14	import { reduce, type ReducedPoint, type Reducer } from "@/lib/dimReduce";
15	import {
16	  DEFAULT_EXPLORER_STATE,
17	  decodeExplorerState,
18	  deleteSavedView,
19	  encodeExplorerState,
20	  loadSavedViews,
21	  saveView,
22	  type ExplorerState,
