24	} from "@/lib/explorerState";
25	
26	interface RawIndex {
27	  points: Array<
28	    ExplorerPoint & {
29	      embedding?: number[];
30	      // The legacy `/api/conclusions/embeddings` endpoint returns
31	      // pre-projected coordinates instead of raw vectors. We accept
32	      // both shapes here so the new Explorer keeps working as the
33	      // backend rolls out the richer payload.
34	      x?: number;
35	      y?: number;
36	    }
37	  >;
38	  edges?: ExplorerEdge[];
39	  embeddingDim?: number;
40	  status?: "ready" | "warming-up";
41	  embeddedCount?: number;
42	  totalCount?: number;
