44	}
45	
46	interface LegacyProjection {
47	  conclusions: Array<{
48	    id: string;
49	    text: string;
50	    topicHint: string;
51	    confidenceTier: string;
52	    x: number;
53	    y: number;
54	  }>;
55	  axes: Array<{ label: string; varianceExplained: number }>;
56	  status?: "ready" | "warming-up";
57	  embeddedCount?: number;
58	  totalCount?: number;
59	  error?: string | null;
60	}
61	
62	function adaptLegacyProjection(legacy: LegacyProjection): {
63	  points: ExplorerPoint[];
64	  preProjected: ReducedPoint[];
65	} {
66	  return {
67	    points: legacy.conclusions.map((c) => ({
68	      id: c.id,
69	      text: c.text,
70	      topicHint: c.topicHint || "",
71	      confidenceTier: c.confidenceTier || "open",
72	      methods: [],
73	      isPrivate: false,
74	    })),
75	    preProjected: legacy.conclusions.map((c) => ({ x: c.x, y: c.y })),
76	  };
77	}
78	
79	export default function ExplorerPage() {
80	  const router = useRouter();
81	  const searchParams = useSearchParams();
82	
