1	import LibraryBrowser from "./LibraryBrowser";
2	import { redirect } from "next/navigation";
3	import { revalidatePath } from "next/cache";
4	import { db } from "@/lib/db";
5	import { canWrite } from "@/lib/roles";
6	import { requireTenantContext } from "@/lib/tenant";
7	
8	/**
9	 * /library — org-wide upload inventory.
10	 *
11	 * The Codex is collective. Every founder can see what's in the library
12	 * and who put it there. Only owners can delete their own entries; peers
13	 * can open a "please delete" request that the owner reviews.
14	 *
15	 * The server component here does only the auth check — all data
16	 * fetching is in the client component so we can reload after every
17	 * mutation (accept / decline / delete / request / cancel) without a
18	 * full page navigation.
19	 */
20	type LibrarySearchParams = {
21	  request?: string;
22	  requested?: string;
23	  error?: string;
24	};
25	
26	async function LibraryContent({
27	  searchParams,
28	}: {
29	  searchParams: Promise<LibrarySearchParams>;
30	}) {
31	  const tenant = await requireTenantContext();
32	  if (!tenant) return null;
33	
34	  const sp = await searchParams;
35	  const requestConclusionId = String(sp.request || "").trim();
36	  const deletionTarget = requestConclusionId
37	    ? await db.conclusion.findFirst({
38	        where: {
39	          id: requestConclusionId,
40	          organizationId: tenant.organizationId,
41	        },
42	        select: {
43	          id: true,
44	          text: true,
45	          confidenceTier: true,
46	          topicHint: true,
47	        },
48	      })
49	    : null;
50	  const existingConclusionDeletionRequest = deletionTarget
51	    ? await db.conclusionDeletionRequest.findFirst({
52	        where: {
53	          conclusionId: deletionTarget.id,
54	          requesterId: tenant.founderId,
55	          status: "pending",
56	        },
57	        select: { id: true },
58	      })
59	    : null;
60	
61	  async function requestConclusionDeletionFromLibrary(formData: FormData) {
62	    "use server";
63	    const conclusionId = String(formData.get("conclusionId") || "").trim();
64	    const reason = String(formData.get("reason") || "").trim();
65	    const currentTenant = await requireTenantContext();
66	    if (!currentTenant) redirect("/login");
67	    if (!conclusionId) redirect("/library?error=missing-conclusion");
68	
69	    if (!canWrite(currentTenant.role)) {
70	      redirect(
71	        `/library?request=${encodeURIComponent(
72	          conclusionId,
73	        )}&error=readonly#conclusion-deletion-request`,
74	      );
75	    }
76	
77	    const conclusion = await db.conclusion.findFirst({
78	      where: {
79	        id: conclusionId,
80	        organizationId: currentTenant.organizationId,
81	      },
82	      select: { id: true },
83	    });
84	    if (!conclusion) {
85	      redirect("/library?error=not-found#conclusion-deletion-request");
86	    }
87	
88	    const existing = await db.conclusionDeletionRequest.findFirst({
89	      where: {
90	        conclusionId,
91	        requesterId: currentTenant.founderId,
92	        status: "pending",
93	      },
94	      select: { id: true },
95	    });
96	
97	    if (!existing) {
98	      const created = await db.conclusionDeletionRequest.create({
99	        data: {
100	          conclusionId,
101	          requesterId: currentTenant.founderId,
102	          reason: reason || "Requested from library peer-review delete flow",
103	        },
104	      });
105	      await db.auditEvent.create({
106	        data: {
107	          organizationId: currentTenant.organizationId,
108	          founderId: currentTenant.founderId,
109	          action: "conclusion_deletion_request",
110	          detail: JSON.stringify({
111	            conclusionId,
112	            requestId: created.id,
113	            source: "library-request-link",
114	          }),
115	        },
116	      });
117	    }
118	
119	    revalidatePath("/library");
120	    revalidatePath(`/conclusions/${conclusionId}`);
121	    redirect(
122	      `/library?request=${encodeURIComponent(
123	        conclusionId,
124	      )}&requested=1#conclusion-deletion-request`,
125	    );
126	  }
127	
128	  return (
129	    <main
130	      style={{
131	        maxWidth: "1000px",
132	        margin: "0 auto",
133	        padding: "2rem 2rem 4rem",
134	      }}
135	    >
136	      <header style={{ marginBottom: "1.75rem" }}>
137	        <h1
138	          style={{
139	            fontFamily: "'Cinzel Decorative', 'Cinzel', serif",
140	            fontSize: "2rem",
141	            letterSpacing: "0.18em",
142	            color: "var(--amber)",
143	            textShadow: "var(--glow-md)",
144	            margin: 0,
145	          }}
146	        >
147	          Bibliotheca
148	        </h1>
149	        <p
150	          className="mono"
151	          style={{
152	            fontSize: "0.62rem",
153	            letterSpacing: "0.28em",
154	            textTransform: "uppercase",
155	            color: "var(--amber-dim)",
156	            marginTop: "0.25rem",
157	            marginBottom: 0,
158	          }}
159	        >
160	          Library · Every upload in the firm
161	        </p>
162	        <p
163	          style={{
164	            fontFamily: "'EB Garamond', serif",
165	            fontStyle: "italic",
166	            fontSize: "1.05rem",
167	            color: "var(--parchment-dim)",
168	            marginTop: "0.6rem",
169	            marginBottom: 0,
170	            lineHeight: 1.55,
171	            maxWidth: "44em",
172	          }}
173	        >
174	          Who contributed what. Owners can delete their own entries
175	          directly. For material you didn&rsquo;t upload, send a deletion
176	          request — the owner decides. Every action leaves an audit
177	          trail.
178	        </p>
179	      </header>
180	
181	      {requestConclusionId ? (
182	        <ConclusionDeletionRequestPanel
183	          conclusion={deletionTarget}
184	          requested={sp.requested === "1"}
185	          error={sp.error || ""}
186	          canRequest={canWrite(tenant.role)}
187	          existingRequestId={existingConclusionDeletionRequest?.id || null}
188	          action={requestConclusionDeletionFromLibrary}
189	        />
190	      ) : null}
191	
192	      <LibraryBrowser />
193	    </main>
194	  );
195	}
196	
197	export default async function LibraryPage({
198	  searchParams,
199	}: {
200	  searchParams: Promise<LibrarySearchParams>;
201	}) {
202	  return LibraryContent({ searchParams });
203	}
204	
205	function ConclusionDeletionRequestPanel({
206	  conclusion,
207	  requested,
208	  error,
209	  canRequest,
210	  existingRequestId,
211	  action,
212	}: {
213	  conclusion: {
214	    id: string;
215	    text: string;
216	    confidenceTier: string;
217	    topicHint: string;
218	  } | null;
219	  requested: boolean;
220	  error: string;
221	  canRequest: boolean;
222	  existingRequestId: string | null;
223	  action: (formData: FormData) => Promise<void>;
224	}) {
225	  return (
226	    <section
227	      id="conclusion-deletion-request"
228	      className="portal-card"
229	      style={{
230	        marginBottom: "1.75rem",
231	        padding: "1rem 1.2rem",
232	        border: "1px solid var(--ember)",
233	        background:
234	          "linear-gradient(180deg, rgba(166,68,45,0.11), rgba(166,68,45,0.03))",
235	      }}
236	    >
237	      <h2
238	        className="mono"
239	        style={{
240	          margin: "0 0 0.6rem",
241	          color: "var(--ember)",
242	          fontSize: "0.65rem",
243	          letterSpacing: "0.24em",
244	          textTransform: "uppercase",
245	        }}
246	      >
247	        Peer-review conclusion deletion
248	      </h2>
249	      {!conclusion ? (
250	        <p style={{ margin: 0, color: "var(--parchment-dim)", fontSize: "0.85rem" }}>
251	          This conclusion is not available in your organization.
252	        </p>
253	      ) : (
254	        <>
255	          <p
256	            style={{
257	              margin: 0,
258	              color: "var(--parchment)",
259	              fontFamily: "'EB Garamond', serif",
260	              fontSize: "1rem",
261	              lineHeight: 1.5,
262	            }}
263	          >
264	            {conclusion.text}
265	          </p>
266	          <p
267	            className="mono"
268	            style={{
269	              margin: "0.4rem 0 0.85rem",
270	              color: "var(--parchment-dim)",
271	              fontSize: "0.6rem",
272	              letterSpacing: "0.14em",
273	              textTransform: "uppercase",
274	            }}
275	          >
276	            {conclusion.confidenceTier} · {conclusion.topicHint || "general"}
277	          </p>
278	
279	          {requested || existingRequestId ? (
280	            <p style={{ color: "var(--amber)", fontSize: "0.82rem", margin: 0 }}>
281	              A pending peer-review deletion request already exists.
282	            </p>
283	          ) : !canRequest ? (
284	            <p style={{ color: "var(--ember)", fontSize: "0.82rem", margin: 0 }}>
285	              Your current role cannot open conclusion deletion requests.
286	            </p>
287	          ) : (
288	            <form action={action}>
289	              <input type="hidden" name="conclusionId" value={conclusion.id} />
290	              <label
291	                className="mono"
292	                htmlFor="conclusion-deletion-reason"
293	                style={{
294	                  display: "block",
295	                  color: "var(--parchment-dim)",
296	                  fontSize: "0.58rem",
297	                  letterSpacing: "0.18em",
298	                  textTransform: "uppercase",
299	                  marginBottom: "0.35rem",
300	                }}
301	              >
302	                Reason for peer review
303	              </label>
