575	                      onClick={() =>
576	                        doRequest(row.id, row.title, founderDisplayName(row.founder))
577	                      }
578	                      style={ghostBtn("amber")}
579	                      title={`Ask ${founderDisplayName(row.founder)} to delete this.`}
580	                    >
581	                      Request deletion
582	                    </button>
583	                  )}
584	                </div>
585	              </div>
586	            </li>
587	          ))}
588	        </ul>
589	      )}
590	
591	      {/* Outgoing history — useful for remembering what you asked for */}
592	      {state.outgoing.length > 0 ? (
