async function ForecastsPulse({ tenant }: { tenant: TenantContext }) {
  const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
  const [surface, settledLastWeek] = await Promise.all([
    getForecastPortfolioSurface(tenant.organizationId).catch((err) => {
      console.error("[dashboard] forecasts portfolio query failed:", err);
      return null;
    }),
    db.forecastBet
      .findMany({
        where: {
          organizationId: tenant.organizationId,
          mode: "PAPER",
          status: "SETTLED",
          settledAt: { gte: weekAgo },
        },
        select: { settlementPnlUsd: true },
      })
      .catch((err) => {
        console.error("[dashboard] forecasts pnl query failed:", err);
        return [];
      }),
  ]);

  const mode = surface?.mode.mode ?? "GATE-BLOCKED";
  const accent =
    mode === "PAPER"
      ? "rgba(160, 211, 170, 0.9)"
      : mode === "LIVE"
        ? "var(--amber)"
        : "var(--ember)";
  const pnl7d = settledLastWeek.reduce((sum, row) => sum + Number(row.settlementPnlUsd ?? 0), 0);

  return (
    <section
      aria-label="Forecasts portfolio pulse"
      style={{
        background: mode === "GATE-BLOCKED" ? "rgba(172, 54, 37, 0.12)" : "rgba(205, 151, 67, 0.08)",
        border: `1px solid ${accent}`,
        borderRadius: 4,
        padding: "0.7rem 0.9rem",
      }}
    >
      <div
        style={{
          alignItems: "baseline",
          display: "flex",
          flexWrap: "wrap",
          gap: "1rem",
          justifyContent: "space-between",
        }}
      >
        <div
          className="mono"
          style={{
            color: accent,
            fontSize: "0.62rem",
            letterSpacing: "0.18em",
            textTransform: "uppercase",
          }}
        >
          Forecasts · {mode}
        </div>
        <Link href="/forecasts/portfolio" style={{ color: "var(--gold)", fontSize: "0.78rem" }}>
          Open portfolio
        </Link>
      </div>
      <p style={{ color: "var(--parchment)", fontSize: "0.82rem", margin: "0.4rem 0 0" }}>
        Paper P&L 7d: {formatDashboardUsd(pnl7d)}; open positions: {surface?.kpis.openPositions ?? 0}.
      </p>
      {surface?.mode.failedGates.length ? (
        <p className="mono" style={{ color: "var(--ember)", fontSize: "0.66rem", margin: "0.35rem 0 0" }}>
          blocked={surface.mode.failedGates.map((gate) => gate.gateName).join(", ")}
        </p>
      ) : null}
    </section>
  );
}

function formatDashboardUsd(value: number): string {
  const formatted = new Intl.NumberFormat("en-US", {
    currency: "USD",
    maximumFractionDigits: 2,
    minimumFractionDigits: 2,
    style: "currency",
  }).format(Math.abs(value));
  return value < 0 ? `-${formatted}` : value > 0 ? `+${formatted}` : formatted;
}

function embeddingHealthColor(health: EmbeddingHealth | null): string {
  if (!health) return "var(--ember)";
  if (health.status === "red") return "var(--ember)";
  if (health.status === "amber") return "var(--amber)";
  return "rgba(160, 211, 170, 0.9)";
}

function getUploadVisibilityScope(tenant: TenantContext): Prisma.UploadWhereInput {
  return {
    OR: [
      { visibility: { not: "private" } },
      { founderId: tenant.founderId },
    ],
  };
}

  embeddingJson String?

  attributedFounderId     String?
  attributedFounder       Founder?                    @relation("ConclusionFounder", fields: [attributedFounderId], references: [id])
  organization            Organization                @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicationReviews      PublicationReview[]
  sources                 ConclusionSource[]
  methodologyProfiles     MethodologyProfile[]
  /// Optional MQS row (1:1). Built by `noosphere mqs backfill`; re-runnable
  /// without rewriting the underlying methodology profile.
  methodologyQualityScore MethodologyQualityScore?
  conclusionMethods       ConclusionMethod[]
  domainBoundVerdicts     DomainBoundVerdict[]
  recalibrationOverride   RecalibrationOverride?
  deletionRequests        ConclusionDeletionRequest[]
  dashboardDismissals     DashboardDismissal[]

  /// Conclusion edit timestamp; the public MQS pill is only shown when the
  /// MQS row's `scoredAt` is at least this recent.
  updatedAt DateTime? @updatedAt

  @@index([organizationId])
  @@index([organizationId, normalizedText])
}

/// Many-to-many bridge Conclusion ↔ Upload.
///
/// Every conclusion that came out of the ingest pipeline has at least
/// one row here tying it back to the upload it was extracted from.
/// When the SAME normalized text appears in multiple uploads, the
/// ingest pipeline reuses the existing Conclusion row and adds a new
/// ConclusionSource row per additional upload, so the upstream count
/// can drop from 2 → 1 → 0 as uploads are deleted.
///
/// Delete semantics (enforced by the app-side delete handlers, NOT by
/// FK cascade — we soft-delete uploads, so the FK's ON DELETE CASCADE
/// would not fire anyway):
///
///   * When an upload is soft-deleted, every ConclusionSource row
///     with that uploadId is hard-deleted.
///   * After that, any Conclusion with zero remaining rows is
///     hard-deleted too (the claim's last source is gone).
///   * Conclusions with sources from other uploads remain, just
///     with one fewer row.
///
/// The FK cascade below still serves as a safety net for the rare
/// case of a hard-delete (org takedown, privacy-law purge).
model ConclusionSource {
  conclusionId String
  uploadId     String
  createdAt    DateTime @default(now())

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  upload     Upload     @relation(fields: [uploadId], references: [id], onDelete: Cascade)

  @@id([conclusionId, uploadId])
  @@index([conclusionId])
  @@index([uploadId])
}

