              background: "transparent",
              border: "1px solid var(--border)",
              color: "var(--parchment)",
              borderRadius: 2,
            }}
          />
          {sp.tier && <input type="hidden" name="tier" value={sp.tier} />}
          {sp.topic && <input type="hidden" name="topic" value={sp.topic} />}
          <button
            type="submit"
            className="btn"
            style={{ fontSize: "0.62rem", padding: "0.3rem 0.65rem" }}
          >
            Search
          </button>
          {q ? (
            <Link
              href={buildClearUrl()}
              className="btn"
              style={{
                fontSize: "0.62rem",
                padding: "0.3rem 0.65rem",
                textDecoration: "none",
              }}
            >
              Clear
            </Link>
          ) : null}
        </form>

        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "0.35rem",
            marginTop: "0.5rem",
            alignItems: "center",
          }}
        >
          <span
            className="mono"
            style={{
              color: "var(--amber-dim)",
              fontSize: "0.58rem",
