              textTransform: "uppercase",
              marginRight: "0.25rem",
            }}
          >
            Tier
          </span>
          <Link
            href={buildTierUrl(null)}
            className="btn"
            style={{
              fontSize: "0.62rem",
              padding: "0.25rem 0.55rem",
              textDecoration: "none",
              ...(sp.tier ? {} : { borderColor: "var(--amber)", color: "var(--amber)" }),
            }}
          >
            All
