              style={{
                fontSize: "0.62rem",
                padding: "0.25rem 0.55rem",
                textDecoration: "none",
                display: "inline-flex",
                alignItems: "center",
                gap: "0.35rem",
                ...(sp.tier === t
                  ? { borderColor: "var(--amber)", color: "var(--amber)" }
                  : {}),
