              className="btn"
              style={{
                fontSize: "0.62rem",
                padding: "0.25rem 0.55rem",
                textDecoration: "none",
              }}
            >
              topic: method
            </Link>
          )}
        </div>

        {q ? (
          <p
            style={{
              fontSize: "0.7rem",
              color: "var(--parchment-dim)",
              margin: "0.45rem 0 0",
            }}
          >
            {total} result{total !== 1 ? "s" : ""} for &ldquo;{q}&rdquo;
          </p>
        ) : null}
      </div>

      {display.length === 0 ? (
        <div
          className="portal-card"
          style={{
            padding: "1.25rem",
            textAlign: "center",
            color: "var(--parchment-dim)",
            fontSize: "0.9rem",
          }}
        >
          No conclusions match the current filters.
        </div>
      ) : (
        <ul
          style={{
            listStyle: "none",
            padding: 0,
            margin: 0,
            display: "grid",
            gap: "0.55rem",
          }}
        >
          {display.map((c) => {
            const sourceUpload = c.sources?.[0]?.upload;
            const confidencePct =
              typeof c.confidence === "number" && c.confidence > 0
                ? Math.round(c.confidence * 100)
                : null;
            return (
              <li
                key={c.id}
                className="portal-card"
                style={{ padding: "0.8rem 1rem" }}
              >
                <Link
                  href={`/conclusions/${c.id}`}
                  style={{
                    textDecoration: "none",
                    color: "inherit",
                    display: "grid",
                    gridTemplateColumns: "auto 1fr",
                    gap: "0.75rem",
                    alignItems: "flex-start",
                  }}
                >
                  <ConfidenceTierSigil tier={c.confidenceTier} />
                  <div style={{ minWidth: 0 }}>
                    <div
                      className="mono"
                      style={{
                        fontSize: "0.58rem",
                        color: "var(--amber-dim)",
                        textTransform: "uppercase",
                        letterSpacing: "0.14em",
                        display: "flex",
                        flexWrap: "wrap",
                        gap: "0.4rem",
                        alignItems: "center",
                      }}
                    >
                      <span style={{ color: "var(--amber)" }}>
                        {c.confidenceTier}
                      </span>
                      {confidencePct !== null ? (
                        <span>· {confidencePct}%</span>
                      ) : null}
                      {c.topicHint ? <span>· {c.topicHint}</span> : null}
                      {c.attributedFounder ? (
                        <span>· {founderDisplayName(c.attributedFounder)}</span>
                      ) : null}
                    </div>
                    <p
                      style={{
                        margin: "0.3rem 0 0",
                        color: "var(--parchment)",
                        lineHeight: 1.45,
                        fontSize: "0.98rem",
                      }}
                    >
                      {c.text}
                    </p>
                    {c.rationale ? (
                      <Excerpt
                        text={c.rationale}
                        lines={2}
                        style={{
                          marginTop: "0.3rem",
                          fontSize: "0.8rem",
                          color: "var(--parchment-dim)",
                          lineHeight: 1.5,
                        }}
                      />
                    ) : null}
                    {sourceUpload ? (
                      <div
                        className="mono"
                        style={{
                          marginTop: "0.4rem",
                          fontSize: "0.58rem",
                          color: "var(--parchment-dim)",
                          letterSpacing: "0.1em",
                          display: "flex",
                          gap: "0.4rem",
                          flexWrap: "wrap",
                        }}
                      >
                        <span style={{ textTransform: "uppercase" }}>
                          source
                        </span>
                        <span style={{ color: "var(--parchment)" }}>
                          {sourceUpload.title}
                        </span>
                        {sourceUpload.sourceType ? (
                          <span>· {sourceUpload.sourceType}</span>
                        ) : null}
                      </div>
                    ) : null}
                  </div>
                </Link>
              </li>
            );
          })}
        </ul>
      )}

      {display.length > 0 ? (
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginTop: "1.25rem",
            padding: "0.75rem 0",
            borderTop: "1px solid var(--border)",
            flexWrap: "wrap",
            gap: "0.5rem",
          }}
        >
          <span style={{ fontSize: "0.7rem", color: "var(--parchment-dim)" }}>
            {total} conclusion{total !== 1 ? "s" : ""} · page {page}
          </span>
          <div style={{ display: "flex", gap: "0.5rem" }}>
            {page > 1 ? (
              <Link
                href={buildPageUrl(page - 1)}
                className="btn"
                style={{ fontSize: "0.62rem", padding: "0.3rem 0.65rem", textDecoration: "none" }}
              >
                ← Previous
              </Link>
            ) : null}
            {hasNext ? (
              <Link
                href={buildPageUrl(page + 1)}
                className="btn"
                style={{ fontSize: "0.62rem", padding: "0.3rem 0.65rem", textDecoration: "none" }}
              >
                Next →
              </Link>
            ) : null}
          </div>
        </div>
      ) : null}
    </main>
  );
}

