                      }
                      style={ghostBtn("amber")}
                      title={`Ask ${founderDisplayName(row.founder)} to delete this.`}
                    >
                      Request deletion
                    </button>
                  )}
                </div>
              </div>
            </li>
          ))}
        </ul>
      )}

      {/* Outgoing history — useful for remembering what you asked for */}
      {state.outgoing.length > 0 ? (
        <details
          style={{
            marginTop: "2rem",
            padding: "0.75rem 1rem",
            border: "1px solid var(--stroke)",
            borderRadius: "4px",
          }}
        >
          <summary
            className="mono"
            style={{
              fontSize: "0.62rem",
              letterSpacing: "0.25em",
              textTransform: "uppercase",
              color: "var(--amber-dim)",
              cursor: "pointer",
            }}
          >
            Your deletion-request history · {state.outgoing.length}
          </summary>
          <ul
            style={{
              listStyle: "none",
              margin: "0.8rem 0 0",
              padding: 0,
              fontSize: "0.85rem",
            }}
          >
            {state.outgoing.map((r) => (
              <li
                key={r.id}
                style={{
                  padding: "0.5rem 0",
                  borderTop: "1px solid var(--stroke)",
                  color: "var(--parchment-dim)",
                }}
              >
                <span style={{ color: "var(--parchment)" }}>
                  “{r.upload.title}”
                </span>
                {" · "}
                <span
                  className="mono"
                  style={{
                    color:
                      r.status === "accepted"
                        ? "var(--success, #4ade80)"
                        : r.status === "declined"
                          ? "var(--ember)"
                          : "var(--amber-dim)",
                    letterSpacing: "0.1em",
                    textTransform: "uppercase",
                    fontSize: "0.7rem",
                  }}
                >
                  {r.status}
                </span>
                {r.decision ? <span> — {r.decision}</span> : null}
                <span
                  className="mono"
                  style={{
                    fontSize: "0.6rem",
                    color: "var(--amber-dim)",
                    marginLeft: "0.5em",
                    letterSpacing: "0.1em",
                  }}
                >
                  {new Date(r.createdAt).toLocaleDateString()}
                </span>
              </li>
            ))}
          </ul>
        </details>
      ) : null}
    </div>
  );
}

function ghostBtn(tone: "amber" | "ember" | "muted"): React.CSSProperties {
  const color =
    tone === "amber"
      ? "var(--amber)"
      : tone === "ember"
        ? "var(--ember)"
        : "var(--parchment-dim)";
  const border =
    tone === "amber"
      ? "var(--amber-dim)"
      : tone === "ember"
        ? "var(--ember)"
        : "var(--stroke)";
  return {
    background: "transparent",
    color,
    border: `1px solid ${border}`,
    padding: "0.25rem 0.65rem",
    fontSize: "0.6rem",
    letterSpacing: "0.18em",
    textTransform: "uppercase",
    cursor: "pointer",
    borderRadius: "2px",
    transition: "all 0.18s ease",
  };
}

function decideBtn(kind: "accept" | "decline"): React.CSSProperties {
  if (kind === "accept") {
    return {
      background: "var(--amber)",
      color: "var(--stone-black, #0a0a0a)",
      border: "1px solid var(--amber)",
      padding: "0.35rem 0.9rem",
      fontSize: "0.6rem",
      letterSpacing: "0.22em",
      textTransform: "uppercase",
      cursor: "pointer",
      borderRadius: "2px",
      fontWeight: 700,
    };
  }
  return {
    background: "transparent",
    color: "var(--parchment)",
    border: "1px solid var(--stroke)",
    padding: "0.35rem 0.9rem",
    fontSize: "0.6rem",
    letterSpacing: "0.22em",
    textTransform: "uppercase",
    cursor: "pointer",
    borderRadius: "2px",
  };
}

