function HealthPanel({
  status,
  embedded,
  total,
  message,
}: {
  status: "loading" | "warming" | "empty" | "error";
  embedded: number;
  total: number;
  message?: string | null;
}) {
  const pct =
    total > 0 ? Math.max(0, Math.min(100, Math.round((embedded / total) * 100))) : 0;
  const tone =
    status === "error"
      ? "var(--ember)"
      : status === "loading"
        ? "var(--info)"
        : "var(--amber)";
  const heading =
    status === "loading"
      ? "Loading projection…"
      : status === "error"
        ? "Projection failed to load"
        : status === "warming"
          ? "Waiting for embeddings"
          : "Not enough embedded conclusions";

  return (
    <section
      className="portal-card"
      style={{
        padding: "1rem 1.1rem",
        borderLeft: `3px solid ${tone}`,
      }}
    >
      <div
        className="mono"
        style={{
          fontSize: "0.6rem",
          letterSpacing: "0.2em",
          textTransform: "uppercase",
          color: tone,
          marginBottom: "0.4rem",
        }}
      >
        Embedding health
      </div>
      <h3
        style={{
          margin: 0,
          fontFamily: "'EB Garamond', serif",
          fontSize: "1.05rem",
          color: "var(--parchment)",
          fontWeight: 500,
        }}
      >
        {heading}
      </h3>
      {status !== "loading" ? (
        <p
          style={{
            margin: "0.45rem 0 0",
            fontSize: "0.85rem",
            color: "var(--parchment-dim)",
            lineHeight: 1.5,
          }}
        >
          {status === "error" ? (
            <>The embeddings API returned an error: {message || "unknown"}.</>
          ) : status === "warming" ? (
            <>
              The Explorer activates once the firm has at least 3 embedded
              conclusions. The data shown elsewhere may look empty because
              embeddings have not yet been populated for these conclusions.
            </>
          ) : (
            <>
              The Explorer needs at least 3 conclusions to project. Add more
              uploads, or wait for the next ingest pass to embed existing
              conclusions.
            </>
          )}
        </p>
      ) : null}
      <div
        className="mono"
        style={{
          marginTop: "0.6rem",
          fontSize: "0.7rem",
          color: "var(--parchment)",
          letterSpacing: "0.08em",
          display: "flex",
          gap: "0.5rem",
          flexWrap: "wrap",
          alignItems: "center",
        }}
      >
        <span>
          embedded {embedded}/{total}
          {total > 0 ? ` (${pct}%)` : ""}
        </span>
        {total > 0 ? (
          <span
            aria-hidden="true"
            style={{
              flex: "1 1 8rem",
              minWidth: "6rem",
              maxWidth: "12rem",
              height: 4,
              background: "var(--stone-mid)",
              borderRadius: 2,
              overflow: "hidden",
            }}
          >
            <span
              style={{
                display: "block",
                width: `${pct}%`,
                height: "100%",
                background: tone,
              }}
            />
          </span>
        ) : null}
      </div>
      {status === "warming" || status === "empty" ? (
        <div
          style={{
            marginTop: "0.75rem",
            display: "flex",
            gap: "0.5rem",
            flexWrap: "wrap",
          }}
        >
          <Link
            href="/upload"
            className="btn"
            style={{
              fontSize: "0.62rem",
              padding: "0.3rem 0.65rem",
              textDecoration: "none",
            }}
          >
            Add an upload
          </Link>
          <Link
            href="/ops"
            className="btn"
            style={{
              fontSize: "0.62rem",
              padding: "0.3rem 0.65rem",
              textDecoration: "none",
            }}
          >
            Open ops console
          </Link>
        </div>
      ) : null}
      {status === "error" ? (
        <div style={{ marginTop: "0.75rem" }}>
          <button
            type="button"
            className="btn"
            onClick={() => {
              if (typeof window !== "undefined") window.location.reload();
            }}
            style={{ fontSize: "0.62rem", padding: "0.3rem 0.65rem" }}
          >
            Retry
          </button>
        </div>
      ) : null}
    </section>
  );
}

